// 1. Defina o componente recebendo props via desestruturação
function Saudacao({ nome, cargo }) {
  return (
    <div>
      <h2>Olá, {nome}!</h2>
      <p>Cargo: {cargo}</p>
    </div>
  );
}

// 2. Passe as props como atributos
function App() {
  return (
    <div>
      <Saudacao nome="Maria" cargo="Dev Frontend" />
      <Saudacao nome="João" cargo="Dev Backend" />
    </div>
  );
}

function Botao({ texto = 'Clique aqui', cor = 'blue' }) {
  return (
    <button style={{ backgroundColor: cor }}>
      {texto}
    </button>
  );
}

// Usa os valores padrão:
<Botao />

// Sobrescreve:
<Botao texto="Enviar" cor="green" />

