challenge.solution:
function Perfil({ nome, idade, linguagem }) {
  return (
    <div>
      <h2>{nome}</h2>
      <p>Idade: {idade} — Linguagem favorita: {linguagem}</p>
    </div>
  );
}

export default function App() {
  return (
    <div>
      <Perfil nome="Ana" idade={25} linguagem="React" />
      <Perfil nome="Carlos" idade={30} linguagem="Vue" />
    </div>
  );
}
